import yfinance as yf
import pandas as pd
from datetime import datetime, timedelta
from database import add_stock, get_stock_by_ticker, save_stock_data, get_stock_data

def fetch_stock_data(ticker, period='1y'):
    try:
        stock = yf.Ticker(ticker)
        info = stock.info

        if not info or 'symbol' not in info:
            return {'error': f'Invalid ticker symbol: {ticker}'}

        hist = stock.history(period=period)

        if hist.empty:
            return {'error': f'No data available for ticker: {ticker}'}

        stock_name = info.get('longName', info.get('shortName', ticker))
        stock_id = add_stock(ticker, stock_name)

        if stock_id is None:
            return {'error': 'Failed to add stock to database'}

        data_list = []
        for date, row in hist.iterrows():
            data_list.append({
                'date': date.strftime('%Y-%m-%d'),
                'open': float(row['Open']),
                'high': float(row['High']),
                'low': float(row['Low']),
                'close': float(row['Close']),
                'volume': int(row['Volume'])
            })

        save_stock_data(stock_id, data_list)

        return {
            'ticker': ticker.upper(),
            'name': stock_name,
            'stock_id': stock_id,
            'data': data_list[-60:],
            'current_price': float(hist['Close'].iloc[-1]),
            'info': {
                'marketCap': info.get('marketCap'),
                'sector': info.get('sector'),
                'industry': info.get('industry')
            }
        }

    except Exception as e:
        return {'error': f'Error fetching stock data: {str(e)}'}

def get_stock_info(ticker):
    try:
        stock_record = get_stock_by_ticker(ticker)
        if not stock_record:
            return {'error': f'Stock {ticker} not found in database'}

        stock_id = stock_record['id']
        data = get_stock_data(stock_id, limit=60)

        data_list = []
        for row in reversed(data):
            data_list.append({
                'date': row['date'],
                'open': row['open'],
                'high': row['high'],
                'low': row['low'],
                'close': row['close'],
                'volume': row['volume']
            })

        return {
            'ticker': stock_record['ticker'],
            'name': stock_record['name'],
            'stock_id': stock_id,
            'data': data_list,
            'current_price': data_list[-1]['close'] if data_list else None
        }

    except Exception as e:
        return {'error': f'Error retrieving stock info: {str(e)}'}

def get_multiple_stocks_data(tickers):
    results = []
    for ticker in tickers:
        stock_record = get_stock_by_ticker(ticker)
        if stock_record:
            data = get_stock_data(stock_record['id'], limit=30)
            if data:
                results.append({
                    'ticker': ticker,
                    'stock_id': stock_record['id'],
                    'prices': [row['close'] for row in reversed(data)]
                })
    return results

