function ClusterInfo({ cluster }) {
  if (!cluster) {
    return <div className="no-data">No cluster data available</div>
  }

  return (
    <div className="cluster-info">
      <div className="cluster-id-section">
        <span className="cluster-label">Cluster ID:</span>
        <span className="cluster-value">#{cluster.cluster_id}</span>
      </div>

      {cluster.similar_stocks && cluster.similar_stocks.length > 0 && (
        <div className="similar-stocks">
          <h4>Similar Stocks:</h4>
          <div className="stocks-list">
            {cluster.similar_stocks.map((stock, index) => (
              <div key={index} className="stock-item">
                <span className="stock-ticker">{stock.ticker}</span>
                <span className="stock-similarity">
                  {(stock.similarity * 100).toFixed(0)}% similar
                </span>
              </div>
            ))}
          </div>
        </div>
      )}

      {cluster.correlation && Object.keys(cluster.correlation).length > 0 && (
        <div className="correlation-list">
          <h4>Top Correlations:</h4>
          {Object.entries(cluster.correlation)
            .sort(([, a], [, b]) => Math.abs(b) - Math.abs(a))
            .slice(0, 5)
            .map(([ticker, corr]) => (
              <div key={ticker} className="correlation-item">
                <span className="corr-ticker">{ticker}</span>
                <div className="corr-bar-container">
                  <div 
                    className={`corr-bar ${corr > 0 ? 'positive' : 'negative'}`}
                    style={{ 
                      width: `${Math.abs(corr) * 100}%`,
                      marginLeft: corr < 0 ? `${100 - Math.abs(corr) * 100}%` : '0'
                    }}
                  />
                </div>
                <span className="corr-value">{corr.toFixed(2)}</span>
              </div>
            ))}
        </div>
      )}
    </div>
  )
}

export default ClusterInfo

frontend/src/components/CorrelationGraph.content:
function CorrelationGraph({ ticker, correlationMatrix }) {
  if (!correlationMatrix || Object.keys(correlationMatrix).length === 0) {
    return <div className="no-data">No correlation data available</div>
  }

  const allTickers = Object.keys(correlationMatrix)
  const targetCorrelations = correlationMatrix[ticker] || {}

  const sortedCorrelations = Object.entries(targetCorrelations)
    .sort(([, a], [, b]) => Math.abs(b) - Math.abs(a))
    .slice(0, 10)

  return (
    <div className="correlation-graph">
      <div className="correlation-matrix">
        {sortedCorrelations.map(([relatedTicker, correlation]) => (
          <div key={relatedTicker} className="correlation-row">
            <div className="correlation-header">
              <span className="ticker-pair">{ticker} - {relatedTicker}</span>
              <span className={`correlation-value ${correlation > 0.5 ? 'strong-positive' : correlation < -0.5 ? 'strong-negative' : ''}`}>
                {correlation.toFixed(3)}
              </span>
            </div>
            <div className="correlation-bar-wrapper">
              <div className="correlation-bar-track">
                <div className="zero-line"></div>
                <div 
                  className={`correlation-bar-fill ${correlation > 0 ? 'positive' : 'negative'}`}
                  style={{
                    width: `${Math.abs(correlation) * 50}%`,
                    [correlation > 0 ? 'left' : 'right']: '50%'
                  }}
                />
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="correlation-legend">
        <div className="legend-item">
          <div className="legend-color positive"></div>
          <span>Positive Correlation</span>
        </div>
        <div className="legend-item">
          <div className="legend-color negative"></div>
          <span>Negative Correlation</span>
        </div>
      </div>
    </div>
  )
}

export default CorrelationGraph

