const API_URL = `${window.location.protocol}//${window.location.hostname}:3000`

function StockPrediction() {
  const [ticker, setTicker] = useState('')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState(null)
  const [predictionData, setPredictionData] = useState(null)
  const [timePredictions, setTimePredictions] = useState({ hourly: null, daily: null })
  const { isConnected, priceUpdates, trackStock, untrackStock } = useWebSocket(API_URL)

  useEffect(() => {
    if (predictionData && ticker) {
      trackStock(ticker)
    }
    return () => {
      if (ticker) {
        untrackStock(ticker)
      }
    }
  }, [ticker, predictionData])

  useEffect(() => {
    if (predictionData && priceUpdates[ticker]) {
      setPredictionData(prev => ({
        ...prev,
        stock_info: {
          ...prev.stock_info,
          current_price: priceUpdates[ticker].price,
          price_change: priceUpdates[ticker].change,
          price_change_percent: priceUpdates[ticker].change_percent
        }
      }))
    }
  }, [priceUpdates, ticker])

  const handlePredict = async () => {
    if (!ticker.trim()) {
      setError('Please enter a stock ticker')
      return
    }

    setLoading(true)
    setError(null)

    try {
      const response = await axios.post(`${API_URL}/predict`, {
        ticker: ticker.toUpperCase(),
        tickers: [ticker.toUpperCase(), 'AAPL', 'GOOGL', 'MSFT', 'AMZN']
      })

      setPredictionData(response.data)
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch prediction')
    } finally {
      setLoading(false)
    }
  }

  const handleAddStock = async () => {
    if (!ticker.trim()) {
      setError('Please enter a stock ticker')
      return
    }

    setLoading(true)
    setError(null)

    try {
      await axios.post(`${API_URL}/add-stock`, {
        ticker: ticker.toUpperCase()
      })

      handlePredict()
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to add stock')
      setLoading(false)
    }
  }

  const handleTimePrediction = (type, prediction) => {
    setTimePredictions(prev => ({
      ...prev,
      [type]: prediction
    }))
  }

  return (
    <div className="stock-prediction">
      <div className="input-section">
        <div className="input-group">
          <input
            type="text"
            value={ticker}
            onChange={(e) => setTicker(e.target.value.toUpperCase())}
            placeholder="Enter stock ticker (e.g., AAPL)"
            className="ticker-input"
            onKeyPress={(e) => e.key === 'Enter' && handlePredict()}
          />
          <button onClick={handlePredict} disabled={loading} className="btn-primary">
            {loading ? 'Loading...' : 'Predict'}
          </button>
          <button onClick={handleAddStock} disabled={loading} className="btn-secondary">
            Add Stock
          </button>
          <div className={`connection-status ${isConnected ? 'connected' : 'disconnected'}`}>
            <span className="status-dot"></span>
            {isConnected ? 'Live Updates' : 'Offline'}
          </div>
        </div>
        {error && <div className="error-message">{error}</div>}
      </div>

      {predictionData && (
        <div className="results-section">
          <div className="stock-header">
            <h2>{predictionData.ticker}</h2>
            <p className="stock-name">{predictionData.stock_info.name}</p>
            <div className="price-info">
              <div className="current-price">
                <span className="label">Current Price:</span>
                <span className="value">${predictionData.stock_info.current_price?.toFixed(2)}</span>
              </div>
              <div className="predicted-price">
                <span className="label">Predicted Price:</span>
                <span className="value">${predictionData.prediction.predicted_price?.toFixed(2)}</span>
              </div>
              <div className="confidence">
                <span className="label">Confidence:</span>
                <span className="value">{(predictionData.prediction.confidence * 100)?.toFixed(0)}%</span>
              </div>
            </div>
          </div>

          <div className="time-predictions-section">
            <TimePredictions 
              ticker={predictionData.ticker} 
              onPrediction={handleTimePrediction}
            />
          </div>

          <div className="grid-container">
            <div className="grid-item full-width">
              <CandlestickChart data={predictionData.stock_info.data} />
            </div>

            <div className="grid-item full-width">
              <VolumeChart data={predictionData.stock_info.data} />
            </div>

            <div className="grid-item full-width">
              <PredictionChart 
                historicalData={predictionData.stock_info.data}
                predictions={{
                  general: predictionData.prediction,
                  hourly: timePredictions.hourly,
                  daily: timePredictions.daily
                }}
              />
            </div>

            <div className="grid-item chart-section">
              <h3>Price History & Prediction</h3>
              <PriceChart 
                data={predictionData.stock_info.data} 
                prediction={predictionData.prediction}
              />
            </div>

            <div className="grid-item sentiment-section">
              <h3>Sentiment Analysis</h3>
              <SentimentDisplay sentiment={predictionData.sentiment} />
            </div>

            <div className="grid-item cluster-section">
              <h3>Cluster Information</h3>
              <ClusterInfo cluster={predictionData.cluster} />
            </div>

            <div className="grid-item correlation-section">
              <h3>Stock Correlations</h3>
              <CorrelationGraph 
                ticker={predictionData.ticker}
                correlationMatrix={predictionData.correlation_matrix} 
              />
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

export default StockPrediction

