import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, Area, ComposedChart } from 'recharts'

function PredictionChart({ historicalData, predictions }) {
  if (!historicalData || historicalData.length === 0) {
    return <div className="chart-placeholder">No historical data for predictions</div>
  }

  const chartData = historicalData.slice(-20).map(item => ({
    date: item.date.substring(5),
    actual: item.close,
    type: 'historical'
  }))

  if (predictions) {
    if (predictions.hourly) {
      chartData.push({
        date: '1hr',
        predicted: predictions.hourly.predicted_price,
        lower: predictions.hourly.confidence_interval?.lower,
        upper: predictions.hourly.confidence_interval?.upper,
        type: 'prediction'
      })
    }

    if (predictions.daily) {
      chartData.push({
        date: 'Next',
        predicted: predictions.daily.predicted_price,
        lower: predictions.daily.confidence_interval?.lower,
        upper: predictions.daily.confidence_interval?.upper,
        type: 'prediction'
      })
    }

    if (predictions.general) {
      chartData.push({
        date: 'GNN',
        predicted: predictions.general.predicted_price,
        type: 'prediction'
      })
    }
  }

  return (
    <div className="chart-container">
      <h3>Price Predictions with Confidence Intervals</h3>
      <ResponsiveContainer width="100%" height={300}>
        <ComposedChart data={chartData}>
          <CartesianGrid strokeDasharray="3 3" stroke="#374151" />
          <XAxis dataKey="date" stroke="#9ca3af" />
          <YAxis stroke="#9ca3af" domain={['auto', 'auto']} />
          <Tooltip 
            contentStyle={{ backgroundColor: '#1f2937', border: '1px solid #374151' }}
            labelStyle={{ color: '#f3f4f6' }}
            formatter={(value) => value ? `$${value.toFixed(2)}` : 'N/A'}
          />
          <Legend />

          <Line 
            type="monotone" 
            dataKey="actual" 
            stroke="#8b5cf6" 
            strokeWidth={2}
            dot={false}
            name="Historical Price"
          />

          <Line 
            type="monotone" 
            dataKey="predicted" 
            stroke="#10b981" 
            strokeWidth={3}
            dot={{ fill: '#10b981', r: 6 }}
            name="Predicted Price"
          />

          <Area
            type="monotone"
            dataKey="upper"
            stroke="#6366f1"
            fill="#6366f1"
            fillOpacity={0.2}
            name="Confidence Upper"
          />

          <Area
            type="monotone"
            dataKey="lower"
            stroke="#6366f1"
            fill="#6366f1"
            fillOpacity={0.2}
            name="Confidence Lower"
          />
        </ComposedChart>
      </ResponsiveContainer>
    </div>
  )
}

export default PredictionChart

