import { useState } from 'react'

function TimePredictions({ ticker, onPrediction }) {
  const [loading, setLoading] = useState({ hourly: false, daily: false })
  const [predictions, setPredictions] = useState({ hourly: null, daily: null })
  const [errors, setErrors] = useState({ hourly: null, daily: null })

  const API_URL = `${window.location.protocol}//${window.location.hostname}:3000`

  const fetchHourlyPrediction = async () => {
    if (!ticker) return

    setLoading(prev => ({ ...prev, hourly: true }))
    setErrors(prev => ({ ...prev, hourly: null }))

    try {
      const response = await fetch(`${API_URL}/predict-hourly`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ticker })
      })

      const data = await response.json()

      if (data.error) {
        setErrors(prev => ({ ...prev, hourly: data.error }))
      } else {
        setPredictions(prev => ({ ...prev, hourly: data.prediction }))
        if (onPrediction) onPrediction('hourly', data.prediction)
      }
    } catch (error) {
      setErrors(prev => ({ ...prev, hourly: 'Failed to fetch hourly prediction' }))
    } finally {
      setLoading(prev => ({ ...prev, hourly: false }))
    }
  }

  const fetchDailyPrediction = async () => {
    if (!ticker) return

    setLoading(prev => ({ ...prev, daily: true }))
    setErrors(prev => ({ ...prev, daily: null }))

    try {
      const response = await fetch(`${API_URL}/predict-daily`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ticker })
      })

      const data = await response.json()

      if (data.error) {
        setErrors(prev => ({ ...prev, daily: data.error }))
      } else {
        setPredictions(prev => ({ ...prev, daily: data.prediction }))
        if (onPrediction) onPrediction('daily', data.prediction)
      }
    } catch (error) {
      setErrors(prev => ({ ...prev, daily: 'Failed to fetch daily prediction' }))
    } finally {
      setLoading(prev => ({ ...prev, daily: false }))
    }
  }

  return (
    <div className="time-predictions">
      <h3>Time-Specific Predictions</h3>
      <div className="prediction-buttons">
        <button 
          onClick={fetchHourlyPrediction} 
          disabled={loading.hourly || !ticker}
          className="predict-button"
        >
          {loading.hourly ? 'Loading...' : '1-Hour Prediction'}
        </button>

        <button 
          onClick={fetchDailyPrediction} 
          disabled={loading.daily || !ticker}
          className="predict-button"
        >
          {loading.daily ? 'Loading...' : 'Next-Day Prediction'}
        </button>
      </div>

      <div className="predictions-display">
        {errors.hourly && <div className="error-message">{errors.hourly}</div>}
        {predictions.hourly && (
          <div className="prediction-card">
            <h4>1-Hour Forecast</h4>
            <div className="prediction-details">
              <p><strong>Current:</strong> ${predictions.hourly.current_price?.toFixed(2)}</p>
              <p><strong>Predicted:</strong> ${predictions.hourly.predicted_price?.toFixed(2)}</p>
              <p className={predictions.hourly.percent_change >= 0 ? 'positive' : 'negative'}>
                <strong>Change:</strong> {predictions.hourly.percent_change?.toFixed(2)}%
              </p>
              <p><strong>Confidence:</strong> {predictions.hourly.confidence?.toFixed(1)}%</p>
            </div>
          </div>
        )}

        {errors.daily && <div className="error-message">{errors.daily}</div>}
        {predictions.daily && (
          <div className="prediction-card">
            <h4>Next-Day Forecast</h4>
            <div className="prediction-details">
              <p><strong>Current:</strong> ${predictions.daily.current_price?.toFixed(2)}</p>
              <p><strong>Predicted:</strong> ${predictions.daily.predicted_price?.toFixed(2)}</p>
              <p className={predictions.daily.percent_change >= 0 ? 'positive' : 'negative'}>
                <strong>Change:</strong> {predictions.daily.percent_change?.toFixed(2)}%
              </p>
              <p><strong>Confidence:</strong> {predictions.daily.confidence?.toFixed(1)}%</p>
              <p><strong>Date:</strong> {predictions.daily.prediction_date}</p>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

export default TimePredictions

